            authnRequest.SetAttribute("Version", "2.0");
            authnRequest.SetAttribute("IssueInstant", request.IssueInstant.ToString("o"));
            authnRequest.SetAttribute("Destination", request.Destination);
            authnRequest.SetAttribute("AssertionConsumerServiceURL", request.AssertionConsumerServiceUrl);
            authnRequest.SetAttribute("ProtocolBinding", "urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST");

