            nameIdPolicy.SetAttribute("Format", request.NameIdFormat);
            nameIdPolicy.SetAttribute("AllowCreate", "true");
            authnRequest.AppendChild(nameIdPolicy);

            // RequestedAuthnContext
            var requestedAuthnContext = doc.CreateElement("samlp", "RequestedAuthnContext", SamlpNamespace);
            requestedAuthnContext.SetAttribute("Comparison", "exact");

            var authnContextClassRef = doc.CreateElement("saml", "AuthnContextClassRef", SamlNamespace);
