    public class SamlXmlSigner : ISamlXmlSigner
    {
        private readonly ILogger<SamlXmlSigner> _logger;

        public SamlXmlSigner(ILogger<SamlXmlSigner> logger)
        {
            _logger = logger;
        }

        /// <summary>
        /// Signs the XML document using RSA-SHA256.
        /// SHA-256 is used instead of SHA-1 because SHA-1 is cryptographically broken.
        /// </summary>
        public void SignXml(XmlDocument document, X509Certificate2 certificate)
        {
            if (document == null)
                throw new ArgumentNullException(nameof(document));
            if (certificate == null)
                throw new ArgumentNullException(nameof(certificate));

            var rsaKey = certificate.GetRSAPrivateKey();
            if (rsaKey == null)
                throw new InvalidOperationException("Certificate does not contain an RSA private key.");

            // Ensure minimum key size of 2048 bits
            if (rsaKey.KeySize < 2048)
                throw new InvalidOperationException(
                    $"RSA key size {rsaKey.KeySize} is too small. Minimum 2048 bits required.");

            var signedXml = new SignedXml(document)
            {
                SigningKey = rsaKey
            };

            // Use SHA-256 — NOT SHA-1
            // SHA-1 has known collision attacks and MUST NOT be used for signatures.
            signedXml.SignedInfo.SignatureMethod = SignedXml.XmlDsigRSASHA256Url;
            signedXml.SignedInfo.CanonicalizationMethod = SignedXml.XmlDsigExcC14NTransformUrl;

            // Reference the entire document
            var reference = new Reference
            {
                Uri = "",
                DigestMethod = SignedXml.XmlDsigSHA256Url // SHA-256 digest
            };

            reference.AddTransform(new XmlDsigEnvelopedSignatureTransform());
            reference.AddTransform(new XmlDsigExcC14NTransform());

            signedXml.AddReference(reference);

            // Include the public key info for verification
            var keyInfo = new KeyInfo();
            keyInfo.AddClause(new KeyInfoX509Data(certificate));
            signedXml.KeyInfo = keyInfo;

            signedXml.ComputeSignature();

            var signatureElement = signedXml.GetXml();

            // Insert signature after Issuer element (SAML spec requirement)
            var issuerElement = document.GetElementsByTagName("Issuer", "urn:oasis:names:tc:SAML:2.0:assertion")[0];
            if (issuerElement?.ParentNode != null)
            {
                issuerElement.ParentNode.InsertAfter(
                    document.ImportNode(signatureElement, true),
                    issuerElement);
            }
            else
            {
                document.DocumentElement?.AppendChild(
                    document.ImportNode(signatureElement, true));
            }

            _logger.LogInformation("SAML AuthnRequest signed successfully with RSA-SHA256.");
        }
    }

