    public class SamlAttributeEncryptor : ISamlAttributeEncryptor
    {
        private readonly ILogger<SamlAttributeEncryptor> _logger;

        public SamlAttributeEncryptor(ILogger<SamlAttributeEncryptor> logger)
        {
            _logger = logger;
        }

        /// <summary>
        /// Encrypts sensitive Attribute elements using AES-256-CBC.
        /// DES and 3DES are NOT used because:
        ///   - DES has a 56-bit key (trivially breakable)
        ///   - 3DES is vulnerable to Sweet32 birthday attacks and is deprecated by NIST
        /// AES-256 is the industry standard for symmetric encryption.
        /// RSA-OAEP is used for key transport (not RSA-PKCS1v1.5 which has Bleichenbacher attacks).
        /// </summary>
        public void EncryptSensitiveElements(XmlDocument document, X509Certificate2 encryptionCertificate)
        {
            if (document == null)
                throw new ArgumentNullException(nameof(document));
            if (encryptionCertificate == null)
                throw new ArgumentNullException(nameof(encryptionCertificate));

            var rsaPublicKey = encryptionCertificate.GetRSAPublicKey();
            if (rsaPublicKey == null)
                throw new InvalidOperationException("Encryption certificate does not contain an RSA public key.");

            if (rsaPublicKey.KeySize < 2048)
                throw new InvalidOperationException(
                    $"RSA key size {rsaPublicKey.KeySize} is too small for encryption. Minimum 2048 bits required.");

            var nsMgr = new XmlNamespaceManager(document.NameTable);
            nsMgr.AddNamespace("saml", "urn:oasis:names:tc:SAML:2.0:assertion");
            nsMgr.AddNamespace("samlp", "urn:oasis:names:tc:SAML:2.0:protocol");

            var extensionsNode = document.SelectSingleNode("//samlp:Extensions", nsMgr);
            if (extensionsNode == null)
            {
                _logger.LogDebug("No Extensions element found; nothing to encrypt.");
                return;
            }

            var attributeNodes = extensionsNode.SelectNodes("saml:Attribute", nsMgr);
            if (attributeNodes == null || attributeNodes.Count == 0)
            {
                _logger.LogDebug("No Attribute elements found in Extensions; nothing to encrypt.");
                return;
            }

            // Encrypt each attribute element
            var elementsToEncrypt = new List<XmlElement>();
            foreach (XmlNode node in attributeNodes)
            {
                if (node is XmlElement element)
                {
                    elementsToEncrypt.Add(element);
                }
            }

            foreach (var element in elementsToEncrypt)
            {
                EncryptElement(document, element, encryptionCertificate);
            }

            _logger.LogInformation("Encrypted {Count} sensitive attribute(s) using AES-256-CBC with RSA-OAEP key transport.",
                elementsToEncrypt.Count);
        }

        private void EncryptElement(XmlDocument document, XmlElement elementToEncrypt, X509Certificate2 certificate)
        {
            // Use AES-256 — secure symmetric encryption
            using var aes = Aes.Create();
            aes.KeySize = 256;
            aes.Mode = CipherMode.CBC;
            aes.Padding = PaddingMode.PKCS7;
            aes.GenerateKey();
            aes.GenerateIV();

            var encryptedXml = new EncryptedXml();
            var encryptedData = new EncryptedData
            {
                Type = EncryptedXml.XmlEncElementUrl,
                EncryptionMethod = new EncryptionMethod(EncryptedXml.XmlEncAES256Url),
                CipherData = new CipherData(encryptedXml.EncryptData(elementToEncrypt, aes, false))
            };

            // Encrypt the AES key with RSA-OAEP (NOT RSA-PKCS1v1.5)
            var encryptedKey = new EncryptedKey();
            var rsaPublicKey = certificate.GetRSAPublicKey()!;
            byte[] encryptedKeyBytes = rsaPublicKey.Encrypt(aes.Key, RSAEncryptionPadding.OaepSHA256);
            encryptedKey.CipherData = new CipherData(encryptedKeyBytes);
            encryptedKey.EncryptionMethod = new EncryptionMethod(EncryptedXml.XmlEncRSAOAEPUrl);

            // Add key info referencing the encryption certificate
            var eki = new KeyInfo();
            eki.AddClause(new KeyInfoX509Data(certificate));
            encryptedKey.KeyInfo = eki;

            encryptedData.KeyInfo = new KeyInfo();
            encryptedData.KeyInfo.AddClause(new KeyInfoEncryptedKey(encryptedKey));

            // Replace the plaintext element with the encrypted version
            EncryptedXml.ReplaceElement(elementToEncrypt, encryptedData, false);
        }
    }

