    public class SamlAuthenticationService : ISamlAuthenticationService
    {
        private readonly ISamlConfigurationProvider _configProvider;
        private readonly ISamlRequestBuilder _requestBuilder;
        private readonly ISamlXmlSigner _signer;
        private readonly ISamlAttributeEncryptor _encryptor;
        private readonly ILogger<SamlAuthenticationService> _logger;

        public SamlAuthenticationService(
            ISamlConfigurationProvider configProvider,
            ISamlRequestBuilder requestBuilder,
            ISamlXmlSigner signer,
            ISamlAttributeEncryptor encryptor,
            ILogger<SamlAuthenticationService> logger)
        {
            _configProvider = configProvider;
            _requestBuilder = requestBuilder;
            _signer = signer;
            _encryptor = encryptor;
            _logger = logger;
        }

        public SamlAuthenticationResult CreateAuthnRequest(Dictionary<string, string>? sensitiveAttributes = null)
        {
            var config = _configProvider.GetConfiguration();

            // Generate a cryptographically random request ID
            var requestId = "_" + GenerateSecureId();

            var request = new SamlAuthnRequest
            {
                Id = requestId,
                IssueInstant = DateTime.UtcNow,
                Issuer = config.EntityId,
                Destination = config.IdpSsoUrl,
                AssertionConsumerServiceUrl = config.AssertionConsumerServiceUrl,
                NameIdFormat = config.NameIdFormat,
                ProviderName = config.EntityId,
                SensitiveAttributes = sensitiveAttributes
            };

            // Build the SAML XML
            var xmlDoc = _requestBuilder.BuildAuthnRequest(request);

            // Encrypt sensitive attributes if encryption cert is available
            var encryptionCert = _configProvider.GetEncryptionCertificate();
            if (encryptionCert != null && sensitiveAttributes != null && sensitiveAttributes.Count > 0)
            {
                _encryptor.EncryptSensitiveElements(xmlDoc, encryptionCert);
            }

            // Sign the document
            var signingCert = _configProvider.GetSigningCertificate();
            _signer.SignXml(xmlDoc, signingCert);

            // Encode for transport
            string samlRequestXml;
            using (var stringWriter = new StringWriter())
            {
                using (var xmlWriter = XmlWriter.Create(stringWriter, new XmlWriterSettings
                {
                    OmitXmlDeclaration = false,
                    Encoding = Encoding.UTF8,
                    Indent = false
                }))
                {
                    xmlDoc.WriteTo(xmlWriter);
                }
                samlRequestXml = stringWriter.ToString();
            }

            // Compress and Base64 encode for HTTP-POST binding
            byte[] samlBytes = Encoding.UTF8.GetBytes(samlRequestXml);
            string base64Request;

            using (var memoryStream = new MemoryStream())
            {
                using (var deflateStream = new System.IO.Compression.DeflateStream(
                    memoryStream, System.IO.Compression.CompressionMode.Compress, leaveOpen: true))
                {
                    deflateStream.Write(samlBytes, 0, samlBytes.Length);
                }
                base64Request = Convert.ToBase64String(memoryStream.ToArray());
            }

            // Generate a secure relay state token
            var relayState = GenerateSecureId();

            _logger.LogInformation("SAML AuthnRequest created with ID: {RequestId}", requestId);

            return new SamlAuthenticationResult
            {
                RequestId = requestId,
                IdpUrl = config.IdpSsoUrl,
                SamlRequestBase64 = base64Request,
                RelayState = relayState
            };
        }

        private static string GenerateSecureId()
        {
            byte[] randomBytes = new byte[32];
            using var rng = RandomNumberGenerator.Create();
            rng.GetBytes(randomBytes);
            return Convert.ToHexString(randomBytes).ToLowerInvariant();
        }
    }

    [ApiController]
    [Route("api/[controller]")]
    public class SamlController : ControllerBase
    {
        private readonly ISamlAuthenticationService _authService;
        private readonly ILogger<SamlController> _logger;

        public SamlController(
            ISamlAuthenticationService authService,
            ILogger<SamlController> logger)
        {
            _authService = authService;
            _logger = logger;
        }

        /// <summary>
        /// Initiates SAML SSO login by generating an AuthnRequest
        /// </summary>
        [HttpGet("login")]
        [ValidateAntiForgeryToken]
        public IActionResult InitiateLogin()
        {
            try
            {
                var result = _authService.CreateAuthnRequest();

                // Return an auto-posting HTML form (HTTP-POST binding)
                var html = GenerateAutoPostForm(result);
                return Content(html, "text/html", Encoding.UTF8);
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Failed to create SAML AuthnRequest.");
                return StatusCode(500, "An error occurred initiating SSO login.");
            }
        }

        /// <summary>
        /// Initiates SAML SSO login with sensitive attributes (encrypted)
        /// </summary>
        [HttpPost("login-with-attributes")]
        [ValidateAntiForgeryToken]
        public IActionResult InitiateLoginWithAttributes([FromBody] Dictionary<string, string>? attributes)
        {
            try
            {
                // Validate and sanitize attribute keys/values
                var sanitizedAttributes = new Dictionary<string, string>();
                if (attributes != null)
                {
                    foreach (var kvp in attributes)
                    {
                        if (string.IsNullOrWhiteSpace(kvp.Key) || kvp.Key.Length > 256)
                            continue;
                        if (kvp.Value != null && kvp.Value.Length > 4096)
                            continue;

                        sanitizedAttributes[kvp.Key.Trim()] = kvp.Value?.Trim() ?? string.Empty;
                    }
                }

                var result = _authService.CreateAuthnRequest(sanitizedAttributes);

                return Ok(new
                {
                    result.IdpUrl,
                    result.SamlRequestBase64,
                    result.RelayState,
                    result.RequestId
                });
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Failed to create SAML AuthnRequest with attributes.");
                return StatusCode(500, "An error occurred initiating SSO login.");
            }
        }

