        private static string GenerateAutoPostForm(SamlAuthenticationResult result)
        {
            // HTML-encode values to prevent XSS
            var encodedUrl = System.Net.WebUtility.HtmlEncode(result.IdpUrl);
            var encodedRequest = System.Net.WebUtility.HtmlEncode(result.SamlRequestBase64);
            var encodedRelayState = System.Net.WebUtility.HtmlEncode(result.RelayState);

            return $@"<!DOCTYPE html>
<html>
<head><title>SSO Redirect</title></head>
