        <input type=""hidden"" name=""SAMLRequest"" value=""{encodedRequest}"" />
        <input type=""hidden"" name=""RelayState"" value=""{encodedRelayState}"" />
        <noscript>
            <input type=""submit"" value=""Continue to SSO"" />
        </noscript>
    </form>
</body>
